<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Conway's Game of Life</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: #0d0d0d;
    color: #e0e0e0;
    font-family: system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    gap: 20px;
    padding: 20px;
  }
  h1 {
    font-size: 1.4rem;
    letter-spacing: 0.15em;
    color: #7fff7f;
    text-transform: uppercase;
  }
  #life {
    display: block;
    border: 2px solid #2a2a2a;
    cursor: crosshair;
    border-radius: 4px;
    image-rendering: pixelated;
  }
  .controls {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    padding: 10px 22px;
    border: none;
    border-radius: 6px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    letter-spacing: 0.05em;
    transition: transform 0.08s, opacity 0.08s;
  }
  button:active { transform: scale(0.95); opacity: 0.85; }
  #step   { background: #2a4a7f; color: #aad4ff; }
  #play   { background: #1a5c2a; color: #7fff7f; }
  #random { background: #5c3a1a; color: #ffcc7f; }
  #clear  { background: #5c1a1a; color: #ff9f9f; }
  #play.running { background: #5c1a3a; color: #ff9fd4; }
  .info {
    font-size: 0.75rem;
    color: #555;
    letter-spacing: 0.05em;
  }
</style>
</head>
<body>
<h1>Conway's Game of Life</h1>
<canvas id="life"></canvas>
<div class="controls">
  <button id="step">Step</button>
  <button id="play">Play</button>
  <button id="random">Random</button>
  <button id="clear">Clear</button>
</div>
<div class="info" id="geninfo">Generation: 0</div>
<script>
(function() {
  const W = 60, H = 60;
  const CELL = 10;
  const canvas = document.getElementById('life');
  canvas.width  = W * CELL;
  canvas.height = H * CELL;
  const ctx = canvas.getContext('2d');

  let grid = new Uint8Array(W * H);
  let generation = 0;
  let running = false;
  let rafId = null;
  let lastTime = 0;
  const FPS = 12;
  const INTERVAL = 1000 / FPS;

  function idx(x, y) { return y * W + x; }

  function get(x, y) {
    if (x < 0 || x >= W || y < 0 || y >= H) return 0;
    return grid[idx(x, y)];
  }

  function set(x, y, v) {
    if (x < 0 || x >= W || y < 0 || y >= H) return;
    grid[idx(x, y)] = v ? 1 : 0;
    draw();
  }

  function clear() {
    grid = new Uint8Array(W * H);
    generation = 0;
    updateGen();
    draw();
  }

  function step() {
    const next = new Uint8Array(W * H);
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const alive = grid[idx(x, y)];
        const n =
          get(x-1,y-1) + get(x,y-1) + get(x+1,y-1) +
          get(x-1,y)                 + get(x+1,y)   +
          get(x-1,y+1) + get(x,y+1) + get(x+1,y+1);
        if (alive) {
          next[idx(x,y)] = (n === 2 || n === 3) ? 1 : 0;
        } else {
          next[idx(x,y)] = (n === 3) ? 1 : 0;
        }
      }
    }
    grid = next;
    generation++;
    updateGen();
    draw();
  }

  function random() {
    for (let i = 0; i < W * H; i++) {
      grid[i] = Math.random() < 0.3 ? 1 : 0;
    }
    generation = 0;
    updateGen();
    draw();
  }

  function updateGen() {
    document.getElementById('geninfo').textContent = 'Generation: ' + generation;
  }

  const ALIVE_COLOR = '#7fff7f';
  const DEAD_COLOR  = '#111111';
  const GRID_COLOR  = '#1a1a1a';

  function draw() {
    ctx.fillStyle = DEAD_COLOR;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.fillStyle = ALIVE_COLOR;
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (grid[idx(x, y)]) {
          ctx.fillRect(x * CELL + 1, y * CELL + 1, CELL - 1, CELL - 1);
        }
      }
    }

    ctx.strokeStyle = GRID_COLOR;
    ctx.lineWidth = 0.5;
    for (let x = 0; x <= W; x++) {
      ctx.beginPath();
      ctx.moveTo(x * CELL, 0);
      ctx.lineTo(x * CELL, H * CELL);
      ctx.stroke();
    }
    for (let y = 0; y <= H; y++) {
      ctx.beginPath();
      ctx.moveTo(0, y * CELL);
      ctx.lineTo(W * CELL, y * CELL);
      ctx.stroke();
    }
  }

  function loop(ts) {
    if (!running) return;
    rafId = requestAnimationFrame(loop);
    if (ts - lastTime >= INTERVAL) {
      lastTime = ts;
      step();
    }
  }

  function togglePlay() {
    running = !running;
    const btn = document.getElementById('play');
    if (running) {
      btn.textContent = 'Pause';
      btn.classList.add('running');
      lastTime = 0;
      rafId = requestAnimationFrame(loop);
    } else {
      btn.textContent = 'Play';
      btn.classList.remove('running');
      if (rafId) cancelAnimationFrame(rafId);
    }
  }

  document.getElementById('step').addEventListener('click', () => { step(); });
  document.getElementById('play').addEventListener('click', togglePlay);
  document.getElementById('random').addEventListener('click', () => { random(); });
  document.getElementById('clear').addEventListener('click', () => { clear(); });

  // Mouse painting
  let painting = false;
  let paintValue = 1;

  function cellFromEvent(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width  / rect.width;
    const scaleY = canvas.height / rect.height;
    const cx = Math.floor((e.clientX - rect.left) * scaleX / CELL);
    const cy = Math.floor((e.clientY - rect.top)  * scaleY / CELL);
    return { x: cx, y: cy };
  }

  canvas.addEventListener('mousedown', e => {
    painting = true;
    const { x, y } = cellFromEvent(e);
    paintValue = get(x, y) ? 0 : 1;
    set(x, y, paintValue);
  });

  canvas.addEventListener('mousemove', e => {
    if (!painting) return;
    const { x, y } = cellFromEvent(e);
    set(x, y, paintValue);
  });

  window.addEventListener('mouseup', () => { painting = false; });

  // Touch support
  canvas.addEventListener('touchstart', e => {
    e.preventDefault();
    painting = true;
    const t = e.touches[0];
    const { x, y } = cellFromEvent(t);
    paintValue = get(x, y) ? 0 : 1;
    set(x, y, paintValue);
  }, { passive: false });

  canvas.addEventListener('touchmove', e => {
    e.preventDefault();
    if (!painting) return;
    const t = e.touches[0];
    const { x, y } = cellFromEvent(t);
    set(x, y, paintValue);
  }, { passive: false });

  window.addEventListener('touchend', () => { painting = false; });

  // Public API
  window.life = {
    w: W,
    h: H,
    get,
    set,
    step,
    clear,
  };

  // Initial state
  random();
})();
</script>
</body>
</html>
